'use client';

import React from 'react';

import type { LabeledOptionDto } from '@/shared/contracts/base';
import { Checkbox, Input, Label, Textarea } from '@/shared/ui/primitives.public';
import { SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { cn } from '@/shared/utils/ui-utils';

import { useBrain } from '../context/BrainContext';
import { type AiBrainAssignment, type AiBrainProvider } from '../settings';

const providerOptions: Array<LabeledOptionDto<AiBrainProvider>> = [
  { value: 'model', label: 'Model' },
  { value: 'agent', label: 'Agent' },
];

export function AssignmentEditor(props: {
  assignment: AiBrainAssignment;
  onChange: (next: AiBrainAssignment) => void;
  readOnly?: boolean;
  allowedProviders?: AiBrainProvider[];
  showSystemPrompt?: boolean;
}): React.JSX.Element {
  const { assignment, onChange, readOnly, allowedProviders, showSystemPrompt = true } = props;

  const { modelQuickPicks, agentQuickPicks } = useBrain();
  const activeAllowedProviders =
    allowedProviders && allowedProviders.length > 0
      ? allowedProviders
      : providerOptions.map((option) => option.value);
  const filteredProviderOptions = providerOptions.filter((option) =>
    activeAllowedProviders.includes(option.value)
  );
  const resolvedProvider = activeAllowedProviders.includes(assignment.provider)
    ? assignment.provider
    : (activeAllowedProviders[0] ?? assignment.provider);
  const enabledCheckboxId = React.useId().replace(/:/g, '');

  const updateField = (patch: Partial<AiBrainAssignment>): void => {
    const next = {
      ...assignment,
      ...patch,
    };
    if (!activeAllowedProviders.includes(next.provider)) {
      next.provider = activeAllowedProviders[0] ?? 'model';
    }
    onChange(next);
  };

  return (
    <div className={cn('grid gap-3', readOnly ? 'opacity-70' : '')} aria-disabled={Boolean(readOnly)}>
      <div className='flex items-center gap-2 text-xs text-gray-300'>
        <Checkbox
          id={enabledCheckboxId}
          checked={assignment.enabled}
          onCheckedChange={(checked: boolean | 'indeterminate') =>
            updateField({ enabled: Boolean(checked) })
          }
          disabled={Boolean(readOnly)}
        />
        <Label htmlFor={enabledCheckboxId} className='cursor-pointer text-xs text-gray-300'>
          Enabled
        </Label>
      </div>

      <div className='grid gap-2 md:grid-cols-2'>
        <div className='space-y-1'>
          <Label className='text-xs text-gray-400'>Provider</Label>
          <SelectSimple
            value={resolvedProvider}
            onValueChange={(value: string) => updateField({ provider: value as AiBrainProvider })}
            options={filteredProviderOptions}
            disabled={Boolean(readOnly) || filteredProviderOptions.length <= 1}
            placeholder='Select provider'
            ariaLabel='Provider'
           title='Select provider'/>
        </div>

        <div className='space-y-1'>
          <Label className='text-xs text-gray-400'>Temperature</Label>
          <Input
            type='number'
            min={0}
            max={2}
            step={0.1}
            value={assignment.temperature ?? ''}
            aria-label='Temperature'
            onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
              updateField({
                temperature: e.target.value === '' ? undefined : Number(e.target.value),
              })
            }
            disabled={Boolean(readOnly)}
           title='Input field'/>
        </div>

        <div className='space-y-1'>
          <Label className='text-xs text-gray-400'>Model ID</Label>
          <Input
            value={assignment.modelId}
            aria-label='Model ID'
            onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
              updateField({ modelId: e.target.value })
            }
            placeholder='gpt-4o-mini'
            disabled={Boolean(readOnly) || resolvedProvider !== 'model'}
           title='gpt-4o-mini'/>
          {modelQuickPicks.length > 0 ? (
            <SelectSimple
              value=''
              onValueChange={(value: string) => updateField({ modelId: value })}
              options={modelQuickPicks}
              placeholder='Pick model preset'
              disabled={Boolean(readOnly) || resolvedProvider !== 'model'}
              size='sm'
              className='mt-1'
              ariaLabel='Model preset'
             title='Pick model preset'/>
          ) : null}
        </div>

        <div className='space-y-1'>
          <Label className='text-xs text-gray-400'>Agent ID</Label>
          <Input
            value={assignment.agentId}
            aria-label='Agent ID'
            onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
              updateField({ agentId: e.target.value })
            }
            placeholder='agent_xxx'
            disabled={Boolean(readOnly) || resolvedProvider !== 'agent'}
           title='agent_xxx'/>
          {agentQuickPicks.length > 0 ? (
            <SelectSimple
              value=''
              onValueChange={(value: string) => updateField({ agentId: value })}
              options={agentQuickPicks}
              placeholder='Pick agent/persona preset'
              disabled={Boolean(readOnly) || resolvedProvider !== 'agent'}
              size='sm'
              className='mt-1'
              ariaLabel='Agent preset'
             title='Pick agent/persona preset'/>
          ) : null}
        </div>

        <div className='space-y-1 md:col-span-2'>
          <Label className='text-xs text-gray-400'>Max tokens</Label>
          <Input
            type='number'
            min={1}
            max={8192}
            step={1}
            value={assignment.maxTokens ?? ''}
            aria-label='Max tokens'
            onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
              updateField({ maxTokens: e.target.value === '' ? undefined : Number(e.target.value) })
            }
            disabled={Boolean(readOnly)}
           title='Input field'/>
        </div>
      </div>

      {showSystemPrompt ? (
        <div className='space-y-1'>
          <Label className='text-xs text-gray-400'>System prompt</Label>
          <Textarea
            value={assignment.systemPrompt ?? ''}
            aria-label='System prompt'
            onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) =>
              updateField({ systemPrompt: e.target.value })
            }
            placeholder='Optional system prompt enforced by Brain'
            disabled={Boolean(readOnly)}
            className='min-h-[120px]'
           title='Optional system prompt enforced by Brain'/>
        </div>
      ) : null}

      <div className='space-y-1'>
        <Label className='text-xs text-gray-400'>Notes</Label>
        <Textarea
          value={assignment.notes ?? ''}
          aria-label='Notes'
          onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) =>
            updateField({ notes: e.target.value })
          }
          placeholder='Optional notes for this assignment'
          disabled={Boolean(readOnly)}
         title='Optional notes for this assignment'/>
      </div>
    </div>
  );
}

'use client';

import { GripVertical, Pencil, Trash2 } from 'lucide-react';
import React from 'react';

import { BRAIN_CATALOG_POOL_LABELS } from '@/shared/lib/ai-brain/catalog-entries';
import type { AiBrainCatalogEntry } from '@/shared/lib/ai-brain/settings';
import { createStrictContext } from '@/shared/lib/react/createStrictContext';
import { Badge } from '@/shared/ui/primitives.public';
import { TreeContextMenu, TreeRow } from '@/shared/ui/data-display.public';
import { cn } from '@/shared/utils/ui-utils';
import { type MasterTreeNode } from '@/shared/utils/master-folder-tree-contract';

export interface BrainCatalogNodeItemProps {
  node: MasterTreeNode;
  entry: AiBrainCatalogEntry;
  depth: number;
  isSelected: boolean;
  isDragging: boolean;
  select: () => void;
}

export type BrainCatalogNodeItemRuntimeValue = {
  onEdit: (entry: AiBrainCatalogEntry) => void;
  onRemove: (entry: AiBrainCatalogEntry) => void;
  isPending: boolean;
};

const {
  Context: BrainCatalogNodeItemRuntimeContext,
  useStrictContext: useBrainCatalogNodeItemRuntime,
} = createStrictContext<BrainCatalogNodeItemRuntimeValue>({
  hookName: 'useBrainCatalogNodeItemRuntime',
  providerName: 'BrainCatalogNodeItemRuntimeProvider',
  displayName: 'BrainCatalogNodeItemRuntimeContext',
});

export { BrainCatalogNodeItemRuntimeContext };

export function BrainCatalogNodeItem(props: BrainCatalogNodeItemProps): React.JSX.Element {
  const { node, entry, depth, isSelected, isDragging, select } = props;

  const { onEdit, onRemove, isPending } = useBrainCatalogNodeItemRuntime();
  const poolLabel = BRAIN_CATALOG_POOL_LABELS[entry.pool] ?? entry.pool;

  return (
    <TreeContextMenu
      items={[
        {
          id: 'edit',
          label: 'Edit item',
          icon: <Pencil className='size-3.5' />,
          onSelect: (): void => onEdit(entry),
        },
        {
          id: 'remove',
          label: 'Remove item',
          icon: <Trash2 className='size-3.5' />,
          tone: 'danger',
          onSelect: (): void => onRemove(entry),
        },
      ]}
    >
      <TreeRow
        depth={depth}
        baseIndent={8}
        indent={12}
        tone='subtle'
        selected={isSelected}
        selectedClassName='bg-muted text-white hover:bg-muted'
        className={cn('relative h-8 text-xs', isDragging && 'opacity-50')}
      >
        <div className='flex h-full w-full min-w-0 items-center gap-1.5 text-left'>
          <button
            type='button'
            className='flex h-full min-w-0 flex-1 items-center gap-1.5 text-left'
            onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
              select();
            }}
            title={node.name}
          >
            <span className='inline-flex h-3.5 w-3.5 shrink-0 items-center justify-center opacity-0 transition-opacity group-hover:opacity-100'>
              <GripVertical className='size-3.5 shrink-0 cursor-grab text-gray-500' aria-hidden='true' />
            </span>

            <span className='min-w-0 flex-1 truncate font-medium text-gray-100'>{node.name}</span>
          </button>

          <Badge
            variant='outline'
            className='h-4 shrink-0 px-1 text-[10px] text-gray-400 border-gray-600/50'
          >
            {poolLabel}
          </Badge>
          <button
            type='button'
            className={cn(
              'inline-flex shrink-0 items-center justify-center rounded p-0.5 text-gray-400 transition',
              'opacity-0 group-hover:opacity-100 hover:bg-gray-700/60',
              isPending ? 'cursor-not-allowed opacity-40' : undefined
            )}
            onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
              onEdit(entry);
            }}
            onMouseDown={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
            }}
            title='Edit item'
            aria-label={`Edit ${node.name}`}
            disabled={isPending}
          >
            <Pencil className='size-3' aria-hidden='true' />
          </button>
          <button
            type='button'
            className={cn(
              'inline-flex shrink-0 items-center justify-center rounded p-0.5 text-gray-400 transition',
              'opacity-0 group-hover:opacity-100 hover:bg-red-500/20 hover:text-red-300',
              isPending ? 'cursor-not-allowed opacity-40' : undefined
            )}
            onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
              onRemove(entry);
            }}
            onMouseDown={(event: React.MouseEvent<HTMLButtonElement>): void => {
              event.stopPropagation();
            }}
            title='Remove item'
            aria-label={`Remove ${node.name}`}
            disabled={isPending}
          >
            <Trash2 className='size-3' aria-hidden='true' />
          </button>
        </div>
      </TreeRow>
    </TreeContextMenu>
  );
}

'use client';

import React, { useCallback, useEffect, useMemo, useRef } from 'react';

import {
  createMasterFolderTreeTransactionAdapter,
  FolderTreeViewportV2,
  useMasterFolderTreeShell,
  type FolderTreeViewportRenderNodeInput,
  type FolderTreeViewportV2Props,
} from '@/shared/lib/foldertree/public';

import {
  buildBrainCatalogMasterNodes,
  createBrainCatalogNodeEntryMap,
  resolveBrainCatalogOrderFromNodes,
} from './brain-catalog-master-tree';
import { BrainCatalogNodeItem, BrainCatalogNodeItemRuntimeContext } from './BrainCatalogNodeItem';

import type { AiBrainCatalogEntry } from '../settings';

export interface BrainCatalogTreeProps {
  entries: AiBrainCatalogEntry[];
  onChange: (entries: AiBrainCatalogEntry[]) => void;
  onEdit: (entry: AiBrainCatalogEntry) => void;
  onRemove: (entry: AiBrainCatalogEntry) => void;
  isPending?: boolean;
}

type BrainCatalogTreeViewportRuntimeValue = Pick<
  FolderTreeViewportV2Props,
  'controller' | 'scrollToNodeRef' | 'rootDropUi' | 'renderNode'
> & {
  isPending: boolean;
};

const BrainCatalogTreeViewportRuntimeContext =
  React.createContext<BrainCatalogTreeViewportRuntimeValue | null>(null);

function useBrainCatalogTreeViewportRuntime(): BrainCatalogTreeViewportRuntimeValue {
  const runtime = React.useContext(BrainCatalogTreeViewportRuntimeContext);
  if (!runtime) {
    throw new Error(
      'useBrainCatalogTreeViewportRuntime must be used within BrainCatalogTreeViewportRuntimeContext.Provider'
    );
  }
  return runtime;
}

function BrainCatalogTreeViewport(): React.JSX.Element {
  const { controller, scrollToNodeRef, rootDropUi, renderNode, isPending } =
    useBrainCatalogTreeViewportRuntime();
  return (
    <FolderTreeViewportV2
      controller={controller}
      scrollToNodeRef={scrollToNodeRef}
      rootDropUi={rootDropUi}
      renderNode={renderNode}
      enableDnd={!isPending}
      emptyLabel='No catalog entries'
    />
  );
}

export function BrainCatalogTree({
  entries,
  onChange,
  onEdit,
  onRemove,
  isPending = false,
}: BrainCatalogTreeProps): React.JSX.Element {
  const masterNodes = useMemo(() => buildBrainCatalogMasterNodes(entries), [entries]);
  const entryByNodeId = useMemo(() => createBrainCatalogNodeEntryMap(entries), [entries]);

  const entryByNodeIdRef = useRef(entryByNodeId);
  useEffect(() => {
    entryByNodeIdRef.current = entryByNodeId;
  }, [entryByNodeId]);

  const onChangeRef = useRef(onChange);
  useEffect(() => {
    onChangeRef.current = onChange;
  }, [onChange]);

  const adapter = useMemo(
    () =>
      createMasterFolderTreeTransactionAdapter({
        onApply: async (tx) => {
          const reordered = resolveBrainCatalogOrderFromNodes(
            tx.nextNodes,
            entryByNodeIdRef.current
          );
          onChangeRef.current(reordered);
        },
      }),
    []
  );

  const {
    appearance: { rootDropUi },
    controller,
    viewport: { scrollToNodeRef },
  } = useMasterFolderTreeShell({
    instance: 'brain_catalog_tree',
    nodes: masterNodes,
    adapter,
  });

  const renderNode = useCallback(
    (input: FolderTreeViewportRenderNodeInput): React.ReactNode => {
      const entry = entryByNodeId.get(input.node.id);
      if (!entry) return null;
      return (
        <BrainCatalogNodeItem
          node={input.node}
          entry={entry}
          depth={input.depth}
          isSelected={input.isSelected}
          isDragging={input.isDragging}
          select={input.select}
        />
      );
    },
    [entryByNodeId]
  );
  const nodeItemRuntimeValue = useMemo(
    () => ({
      onEdit,
      onRemove,
      isPending,
    }),
    [isPending, onEdit, onRemove]
  );
  const viewportRuntimeValue = useMemo<BrainCatalogTreeViewportRuntimeValue>(
    () => ({
      controller,
      scrollToNodeRef,
      rootDropUi,
      renderNode,
      isPending,
    }),
    [controller, scrollToNodeRef, rootDropUi, renderNode, isPending]
  );

  return (
    <BrainCatalogNodeItemRuntimeContext.Provider value={nodeItemRuntimeValue}>
      <BrainCatalogTreeViewportRuntimeContext.Provider value={viewportRuntimeValue}>
        <BrainCatalogTreeViewport />
      </BrainCatalogTreeViewportRuntimeContext.Provider>
    </BrainCatalogNodeItemRuntimeContext.Provider>
  );
}

'use client';

import React, { useEffect, useMemo, useState } from 'react';

import { internalError } from '@/shared/errors/app-error';
import { Checkbox, Label } from '@/shared/ui/primitives.public';
import { FormModal } from '@/shared/ui/forms-and-actions.public';

import { useBrain } from '../context/BrainContext';
import {
  getBrainCapabilityDefinition,
  resolveBrainAssignment,
  type AiBrainAssignment,
  type AiBrainCapabilityKey,
} from '../settings';
import { AssignmentEditor } from './AssignmentEditor';
import {
  useOptionalBrainRoutingActionsContext,
  useOptionalBrainRoutingStateContext,
} from './BrainRoutingContext';

type BrainRoutingEditModalState = {
  overrideEnabled: boolean;
  assignment: AiBrainAssignment;
};

export interface BrainRoutingEditModalProps {
  open?: boolean;
  capability?: AiBrainCapabilityKey | null;
  onClose?: () => void;
}

export function BrainRoutingEditModal(props: BrainRoutingEditModalProps): React.JSX.Element | null {
  const stateContext = useOptionalBrainRoutingStateContext();
  const actionsContext = useOptionalBrainRoutingActionsContext();
  const open = props.open ?? Boolean(stateContext?.editingCapability);
  const capability = props.capability ?? stateContext?.editingCapability ?? null;
  const onClose = props.onClose ?? actionsContext?.onCloseEdit;

  const {
    settings,
    effectiveCapabilityAssignments,
    handleCapabilityChange,
    clearCapabilityOverride,
  } = useBrain();
  const [state, setState] = useState<BrainRoutingEditModalState | null>(null);
  const overrideCheckboxId = React.useId().replace(/:/g, '');

  const capabilityDefinition = useMemo(
    () => (capability ? getBrainCapabilityDefinition(capability) : null),
    [capability]
  );

  useEffect(() => {
    if (!open || !capability) {
      setState(null);
      return;
    }
    const overrideEnabled = Boolean(settings.capabilities[capability]);
    const assignment = overrideEnabled
      ? (settings.capabilities[capability] ?? effectiveCapabilityAssignments[capability])
      : effectiveCapabilityAssignments[capability];
    setState({
      overrideEnabled,
      assignment,
    });
  }, [capability, effectiveCapabilityAssignments, open, settings.capabilities]);

  if (!open || !capability || !capabilityDefinition || !state) return null;
  if (!onClose) {
    throw internalError(
      'BrainRoutingEditModal must be used within BrainRoutingProvider or receive explicit modal props'
    );
  }

  const featureEnabled = resolveBrainAssignment(settings, capabilityDefinition.feature).enabled;
  const sourceLabel = !featureEnabled
    ? 'Feature disabled'
    : settings.capabilities[capability]
      ? 'Capability override'
      : settings.assignments[capabilityDefinition.feature]
        ? 'Feature fallback'
        : 'Global defaults';

  const allowedProviders =
    capabilityDefinition.policy === 'agent-or-model'
      ? (['model', 'agent'] as const)
      : (['model'] as const);

  const handleSave = (): void => {
    if (state.overrideEnabled) {
      handleCapabilityChange(capability, state.assignment);
    } else {
      clearCapabilityOverride(capability);
    }
    onClose();
  };

  return (
    <FormModal
      open={open}
      onClose={onClose}
      title={`Edit Route: ${capabilityDefinition.label}`}
      subtitle='Changes are staged locally. Use Save in the Brain header to persist.'
      onSave={handleSave}
      saveText='Apply'
      size='lg'
    >
      <div className='space-y-4'>
        <div className='rounded-md border border-border/60 bg-card/40 p-3 text-xs text-gray-300'>
          <div className='font-semibold text-gray-100'>{capability}</div>
          <div className='mt-1 text-gray-400'>
            Source: <span className='text-gray-300'>{sourceLabel}</span>
          </div>
        </div>

        <div className='flex items-center gap-2 text-xs text-gray-300'>
          <Checkbox
            id={overrideCheckboxId}
            checked={state.overrideEnabled}
            onCheckedChange={(checked: boolean | 'indeterminate') => {
              const enabled = Boolean(checked);
              setState((prev) => {
                if (!prev) return prev;
                if (enabled === prev.overrideEnabled) return prev;
                return {
                  overrideEnabled: enabled,
                  assignment: enabled
                    ? effectiveCapabilityAssignments[capability]
                    : prev.assignment,
                };
              });
            }}
          />
          <Label htmlFor={overrideCheckboxId} className='cursor-pointer text-xs text-gray-300'>
            Use capability-specific override
          </Label>
        </div>

        <AssignmentEditor
          assignment={state.assignment}
          onChange={(next: AiBrainAssignment) => {
            setState((prev) => (prev ? { ...prev, assignment: next } : prev));
          }}
          readOnly={!state.overrideEnabled}
          allowedProviders={[...allowedProviders]}
        />
        {!featureEnabled ? (
          <div className='text-[11px] text-amber-300'>
            This feature is currently off. Route settings are staged, but they will stay inactive
            until the feature is turned back on.
          </div>
        ) : null}
        {!state.overrideEnabled ? (
          <div className='text-[11px] text-gray-500'>
            Override is off. Saving will clear this route override and use fallback inheritance.
          </div>
        ) : null}
      </div>
    </FormModal>
  );
}

'use client';

import React, { useCallback, useMemo } from 'react';

import {
  FolderTreeViewportV2,
  useMasterFolderTreeShell,
  type FolderTreeViewportRenderNodeInput,
} from '@/shared/lib/foldertree/public';
import { internalError } from '@/shared/errors/app-error';

import { getBrainCapabilityDefinition } from '../settings';
import {
  buildBrainRoutingMasterNodes,
  createBrainRoutingCapabilityNodeMap,
  createBrainRoutingFeatureNodeMap,
  ROUTING_GROUPS,
  toBrainRoutingFeatureNodeId,
} from './brain-routing-master-tree';
import {
  BrainRoutingCapabilityNodeItem,
  BrainRoutingCapabilityNodeItemRuntimeContext,
} from './BrainRoutingCapabilityNodeItem';
import {
  useOptionalBrainRoutingActionsContext,
  useOptionalBrainRoutingStateContext,
} from './BrainRoutingContext';
import { BrainRoutingFeatureNodeItem } from './BrainRoutingFeatureNodeItem';

import type { AiBrainAssignment, AiBrainCapabilityKey, AiBrainSettings } from '../settings';
import type { AiBrainFeature } from '../settings';

export interface BrainRoutingTreeProps {
  settings?: AiBrainSettings;
  effectiveAssignments?: Record<AiBrainFeature, AiBrainAssignment>;
  effectiveCapabilityAssignments?: Record<AiBrainCapabilityKey, AiBrainAssignment>;
  onToggleFeatureEnabled?: (feature: AiBrainFeature, enabled: boolean) => void;
  onToggleEnabled?: (capability: AiBrainCapabilityKey, enabled: boolean) => void;
  onEdit?: (capability: AiBrainCapabilityKey) => void;
  isPending?: boolean;
}

export function BrainRoutingTree(props: BrainRoutingTreeProps): React.JSX.Element {
  const stateContext = useOptionalBrainRoutingStateContext();
  const actionsContext = useOptionalBrainRoutingActionsContext();

  const settings = props.settings ?? stateContext?.settings;
  const effectiveAssignments = props.effectiveAssignments ?? stateContext?.effectiveAssignments;
  const effectiveCapabilityAssignments =
    props.effectiveCapabilityAssignments ?? stateContext?.effectiveCapabilityAssignments;
  const onToggleFeatureEnabled =
    props.onToggleFeatureEnabled ?? actionsContext?.onToggleFeatureEnabled;
  const onToggleEnabled = props.onToggleEnabled ?? actionsContext?.onToggleEnabled;
  const onEdit = props.onEdit ?? actionsContext?.onEdit;
  const isPending = props.isPending ?? stateContext?.isPending ?? false;

  if (
    !settings ||
    !effectiveAssignments ||
    !effectiveCapabilityAssignments ||
    !onToggleFeatureEnabled ||
    !onToggleEnabled ||
    !onEdit
  ) {
    throw internalError(
      'BrainRoutingTree must be used within BrainRoutingProvider or receive explicit routing props'
    );
  }

  const masterNodes = useMemo(() => buildBrainRoutingMasterNodes(), []);
  const featureByNodeId = useMemo(() => createBrainRoutingFeatureNodeMap(), []);
  const capabilityByNodeId = useMemo(() => createBrainRoutingCapabilityNodeMap(), []);
  const initialExpandedNodeIds = useMemo(
    () => ROUTING_GROUPS.map((group) => toBrainRoutingFeatureNodeId(group.key)),
    []
  );

  const {
    appearance: { rootDropUi },
    controller,
    viewport: { scrollToNodeRef },
  } = useMasterFolderTreeShell({
    instance: 'brain_routing_tree',
    nodes: masterNodes,
    initiallyExpandedNodeIds: initialExpandedNodeIds,
  });

  const renderNode = useCallback(
    (input: FolderTreeViewportRenderNodeInput): React.ReactNode => {
      const featureGroup = featureByNodeId.get(input.node.id);
      if (featureGroup) {
        return (
          <BrainRoutingFeatureNodeItem
            node={input.node}
            group={featureGroup}
            depth={input.depth}
            hasChildren={input.hasChildren}
            isExpanded={input.isExpanded}
            isSelected={input.isSelected}
            isDragging={input.isDragging}
            select={input.select}
            toggleExpand={input.toggleExpand}
            enabled={effectiveAssignments[featureGroup.key].enabled}
            isPending={isPending}
            onToggleEnabled={onToggleFeatureEnabled}
          />
        );
      }

      const capability = capabilityByNodeId.get(input.node.id);
      if (!capability) return null;

      const definition = getBrainCapabilityDefinition(capability);
      const featureEnabled = effectiveAssignments[definition.feature].enabled;
      const capabilityOverrideEnabled = Boolean(settings.capabilities[capability]);
      const assignment = capabilityOverrideEnabled
        ? (settings.capabilities[capability] ?? effectiveCapabilityAssignments[capability])
        : effectiveCapabilityAssignments[capability];
      const sourceLabel = !featureEnabled
        ? 'Feature disabled'
        : capabilityOverrideEnabled
          ? 'Capability override'
          : settings.assignments[definition.feature]
            ? 'Feature fallback'
            : 'Global defaults';

      return (
        <BrainRoutingCapabilityNodeItem
          node={input.node}
          capability={capability}
          depth={input.depth}
          isSelected={input.isSelected}
          isDragging={input.isDragging}
          select={input.select}
          enabled={featureEnabled ? assignment.enabled : false}
          sourceLabel={sourceLabel}
          toggleDisabled={!featureEnabled}
        />
      );
    },
    [
      effectiveAssignments,
      capabilityByNodeId,
      effectiveCapabilityAssignments,
      featureByNodeId,
      isPending,
      settings.assignments,
      settings.capabilities,
      onToggleFeatureEnabled,
    ]
  );
  const capabilityNodeRuntimeValue = useMemo(
    () => ({
      onToggleEnabled,
      onEdit,
      isPending,
    }),
    [isPending, onEdit, onToggleEnabled]
  );

  return (
    <BrainRoutingCapabilityNodeItemRuntimeContext.Provider value={capabilityNodeRuntimeValue}>
      <FolderTreeViewportV2
        controller={controller}
        scrollToNodeRef={scrollToNodeRef}
        rootDropUi={rootDropUi}
        renderNode={renderNode}
        enableDnd={false}
        emptyLabel='No routing capabilities'
      />
    </BrainRoutingCapabilityNodeItemRuntimeContext.Provider>
  );
}

