                          enabledVariant='blue'
                          disabledVariant='gray'
                          onToggle={(nextEnabled: boolean): void =>
                            toggleOverride(feature.key, nextEnabled)
                          }
                        />
                      </div>
                    </div>

                    <AssignmentEditor
                      assignment={featureAssignment}
                      onChange={(next: AiBrainAssignment) =>
