                      </div>
                    ) : null}
                    {!featureAssignment.enabled ? (
                      <div className='text-[11px] text-amber-300'>
                        Feature is off. Route-level settings are preserved, but this feature will
                        stay inactive until you turn it back on.
                      </div>
                    ) : null}
                  </div>
                </Card>
              );
            })}
          </div>
        </div>
      </CollapsibleSection>
    </div>
  );
